import React from 'react';
import PhotoSide from '../components/PhotoSide';
import { Outlet, useLocation } from 'react-router-dom';
import { AnimatePresence, motion } from 'framer-motion';
import './AuthLayout.css';

function AuthLayout() {
  const location = useLocation();

  // Роуты, где нужно отобразить форму справа
  const reverseRoutes = ['/forgot-password', '/reset-password'];
  const isReverse = reverseRoutes.includes(location.pathname);

  return (
    <div className={`auth-container ${isReverse ? 'reverse' : ''}`}>
      <motion.div
        className="photo-side"
        key="photo"
        initial={{ x: 0 }}
        animate={{ x: 0 }}
        exit={{ x: -100, opacity: 0 }}
        transition={{ duration: 0.4 }}
      >
        <PhotoSide />
      </motion.div>

      <div className="form-side">
        <AnimatePresence mode="wait">
          <motion.div
            key={location.pathname}
            initial={{ x: 100, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            exit={{ x: -100, opacity: 0 }}
            transition={{ duration: 0.4 }}
          >
            <Outlet />
          </motion.div>
        </AnimatePresence>
      </div>
    </div>
  );
}

export default AuthLayout;
